#include <bits/stdc++.h>
using namespace std;

const long long INF=4e18;
int n,a[5005],p[5005][5005];
long long s[5005],dp[5005][5005];

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        s[i]=s[i-1]+a[i];
        p[i][i]=i;
        dp[i][i]=0;
    }

    for(int len=2;len<=n;len++){
        for(int i=1;i+len-1<=n;i++){
            int j=i+len-1;
            dp[i][j]=INF;

            int L=p[i][j-1];
            int R=p[i+1][j];

            // 边界处理，避免访问未初始化的 p[i+1][j]
            if(i+1>j) R=j-1;
            if(L< i) L=i;
            if(R>j-1) R=j-1;

            for(int k=L;k<=R;k++){
                long long val=dp[i][k]+dp[k+1][j]+s[j]-s[i-1];
                if(val<dp[i][j]){
                    dp[i][j]=val;
                    p[i][j]=k;
                }
            }
        }
    }

    printf("%lld\n",dp[1][n]);
    return 0;
}
